235	      // Auto-group column: sort by most recently modified item in each group.
236	      // sort:'desc' is the default direction (newest first); clicking the header
237	      // toggles asc (oldest first) then clears, falling back to alphabetical.
238	      autoGroupColumnDef: {
239	        sort: 'desc',
240	        comparator: (valueA: any, valueB: any, nodeA: any, nodeB: any) => {
241	          const maxDate = (node: any): number => {
242	            // Use childrenAfterFilter (visible items only) so the Step filter doesn't
243	            // let hidden items with newer dates inflate a group's apparent recency.
244	            const leaves: any[] = node.childrenAfterFilter || node.allLeafChildren || [];
245	            let max = 0;
246	            for (const leaf of leaves) {
247	              // Recurse into sub-groups if any exist
248	              if (leaf.group) {
249	                const sub = maxDate(leaf);
250	                if (sub > max) max = sub;
251	              } else {
252	                const d = leaf.data?.['Date Modified'];
253	                if (d) {
254	                  const t = new Date(d).getTime();
255	                  if (!isNaN(t) && t > max) max = t;
256	                }
257	              }
258	            }
259	            return max;
260	          };
261	          // Return A−B; AG-Grid negates this for 'desc', so highest (newest) comes first
