315	      postSortRows: (params: any) => {
316	        const nodes: any[] = params.nodes;
317	        if (!nodes.length || !nodes[0].group) return;
318	        const maxDate = (node: any): number => {
319	          // childrenAfterFilter is populated after the filter step, which runs before
320	          // sort; fall back to allLeafChildren on the first render before filter runs.
321	          const leaves: any[] = node.childrenAfterFilter?.length
322	            ? node.childrenAfterFilter
323	            : (node.allLeafChildren || []);
324	          let max = 0;
325	          for (const leaf of leaves) {
326	            const d = leaf.data?.['Date Modified'];
327	            if (d) {
328	              const t = new Date(d).getTime();
329	              if (!isNaN(t) && t > max) max = t;
330	            }
331	          }
332	          return max;
333	        };
334	        nodes.sort((a: any, b: any) => maxDate(b) - maxDate(a));
