370	  private applyRfqViewListFromApi(views: any[], def: { view_name: string } | null): void {
371	    if (views && views.length) {
372	      this.viewLayouts = views.map((v: any) => ({
373	        layout_name: v.view_name,
374	        is_default: !!v.is_default
375	      }));
376	    } else {
377	      this.viewLayouts = [{ layout_name: 'Default' }];
378	    }
379	    const defaultName = def?.view_name;
380	    const match = defaultName && this.viewLayouts.find((v) => v.layout_name === defaultName);
381	    this.selectedViewLayout = match || this.viewLayouts[0];
