384	  private handleSetFillValue = (fillOperationParams) => {
385	      // colId is lowercase (e.g. "status"); field is the display name (e.g. "Status").
386	      // isDropdownColumn expects colId, so use getColId() — not colDef.field.
387	      const colId = fillOperationParams.column.getColId();
388	      const field = fillOperationParams.column.colDef.field;
389	      if (!this.isDropdownColumn(colId)) return false;
390	      for (var i = 0; this.rowData.length > i; i++) {
391	        if (this.rowData[i][field]) {
392	          const rowVal = this.rowData[i][field];
393	          if (rowVal.title == fillOperationParams.values[0] ||
394	            rowVal.RFQGroup_name == fillOperationParams.values[0] ||
395	            rowVal.data == fillOperationParams.values[0]) {
396	            if (rowVal.data) {
397	              this.findMGfromArray(rowVal, this.rowData);
398	              return { title: rowVal.data };
399	            } else {
400	              // Return the full dropdown object ({title, id, …}) so the valueSetter
401	              // receives the same shape it would from a normal cell edit.
402	              return rowVal;
403	            }
404	          }
405	        }
406	      }
407	      return fillOperationParams.values[0];
408	    };
