444	  private applyGridViewStateForViewName(layoutName: string): void {
445	    if (!this.gridApi || !layoutName) {
446	      return;
447	    }
448	    this.itemService.getGridViewState({ grid_id: 'rfq', view_name: layoutName }).subscribe((res: any) => {
449	      if (res) {
450	        if (res.column_state && res.column_state.length > 0) {
451	          // If the saved state has no explicit sort on the auto-group column (e.g. it was
452	          // saved before the date-based sort was introduced), default it to 'desc' so groups
453	          // always load newest-first unless the user deliberately saved a different direction.
454	          const AUTO_GROUP_COL = 'ag-Grid-AutoColumn';
455	          const savedAutoGroupSort = res.column_state.find((s: any) => s.colId === AUTO_GROUP_COL)?.sort;
456	          const state = savedAutoGroupSort
457	            ? res.column_state
458	            : [
459	                ...res.column_state.filter((s: any) => s.colId !== AUTO_GROUP_COL),
460	                { colId: AUTO_GROUP_COL, sort: 'desc' }
461	              ];
462	          this.gridApi.applyColumnState({ state, applyOrder: true });
463	          this._saveViewStateToSession();
464	        }
465	        const fm = res.filter_model;
466	        const hasFilterModel = fm && typeof fm === 'object' && Object.keys(fm).length > 0;
467	        if (hasFilterModel) {
468	          setTimeout(() => {
469	            this.gridApi.setFilterModel(fm);
470	            this._saveViewStateToSession();
471	            this.afterViewFilterAppliedForDefaultStep(res);
472	          }, 200);
473	        } else {
474	          this.afterViewFilterAppliedForDefaultStep(res);
475	        }
476	      } else {
477	        this.itemService
478	          .getSelectedGridView({ layout_name: layoutName, grid_id: 'rfq' })
479	          .subscribe(async (legacyRes: any) => {
480	            if (legacyRes.length > 0) {
481	              const currentColIds = new Set(this.gridApi.getColumns().map((col) => col.getColId()));
482	              const savedColIds = new Set(legacyRes.map((s: any) => s.colId));
483	              const validState = legacyRes.filter((s: any) => currentColIds.has(s.colId));
484	              const newCols = this.colHeaders
485	                .filter((col: any) => {
486	                  const colId = col.colId || col.field;
487	                  return currentColIds.has(colId) && !savedColIds.has(colId);
488	                })
489	                .map((col: any, i: number) => ({
490	                  colId: col.colId || col.field,
491	                  hide: false,
492	                  order: Math.max(...validState.map((s: any) => s.order || 0), -1) + 1 + i
493	                }));
494	              this.gridApi.applyColumnState({ state: [...validState, ...newCols], applyOrder: true });
495	              this._saveViewStateToSession();
496	            }
497	            this.afterViewFilterAppliedForDefaultStep({ filter_model: null });
498	          });
499	      }

