570	   * Filters columns based on user role
571	   * If a column has a 'roles' property, only show it if the user's role is included
572	   * If a column has no 'roles' property, it's visible to all users
573	   */
574	  private filterColumnsByRole(colHeaders: any[], role: string): any[] {
575	    // If no role is provided, return all columns
576	    if (!role) {
577	      return colHeaders;
578	    }
579	
580	    return colHeaders.filter((col: any) => {
581	      // If column has no roles property or empty roles array, it's visible to all
582	      if (!col.roles || !Array.isArray(col.roles) || col.roles.length === 0) {
583	        return true;
584	      }
585	
586	      // Check if user's role is in the allowed roles array
587	      return col.roles.includes(role);
588	    });
589	  }
