666	          typeof originalEditable === 'function'
667	            ? !!originalEditable(params)
668	            : originalEditable !== false;
669	        if (!baseEditable) {
670	          return false;
671	        }
672	        return this.canCurrentSalesUserEditDetailCells();
673	      },
