1276	   * A vendor quote row sorts to the bottom of the detail grid when it has no
1277	   * usable price (blank / zero / negative) or the factory declined to quote
1278	   * (req_status == 1). Used by the price default-sort comparator.
1279	   */
1280	  private isUnpricedOrDeclined(data: any): boolean {
1281	    if (!data) return true;
1282	    if (data.req_status == 1) return true;
1283	    const price = this.toPrice(data?.['Price']);
1284	    return price <= 0;
