1287	  /**
1288	   * Wires the detail grid's default sort: price ascending as the primary sort,
1289	   * with unpriced/declined rows pushed to the bottom. Mutates the matching
1290	   * colDef in place. The comparator reads the row's `Price` directly so it is
1291	   * independent of the column's colId/field/valueGetter.
1292	   */
1293	  private applyDefaultPriceSort(colHeaders: any[]): void {
1294	    if (!Array.isArray(colHeaders)) return;
1295	    const isPriceCol = (c: any) => c?.colId === 'quote_price' || c?.colId === 'price';
1296	    // Prefer a visible price column; fall back to any price column.
1297	    const priceCol =
1298	      colHeaders.find(c => isPriceCol(c) && c?.hide !== true) ||
1299	      colHeaders.find(c => isPriceCol(c));
1300	    if (!priceCol) return;
1301	
1302	    priceCol.sort = 'asc';
1303	    priceCol.sortIndex = 0;
1304	    priceCol.comparator = (_valueA: any, _valueB: any, nodeA: any, nodeB: any) => {
1305	      const aBottom = this.isUnpricedOrDeclined(nodeA?.data);
1306	      const bBottom = this.isUnpricedOrDeclined(nodeB?.data);
1307	      if (aBottom && bBottom) return 0;
1308	      if (aBottom) return 1;
1309	      if (bBottom) return -1;
1310	      return this.toPrice(nodeA?.data?.['Price']) - this.toPrice(nodeB?.data?.['Price']);
1311	    };
1312	  }
